// src/App.js
import React, { useState, useEffect } from "react";
import Dice from "react-dice-roll";

// --- Board Image path ---
const boardImage = "/torahpoly_board.png";

// --- Red Properties ---
const schemRoyalEstates = {
  type: "property",
  name: "Schem Royal Estates",
  colorGroup: "red",
  price: 300,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 800 },
  buildCost: { house: 200, hotel: 300 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const schemYosephGardens = {
  type: "property",
  name: "Schem Yoseph Gardens",
  colorGroup: "red",
  price: 300,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 800 },
  buildCost: { house: 200, hotel: 300 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const schemDreamResorts = {
  type: "property",
  name: "Schem Dream Resorts",
  colorGroup: "red",
  price: 300,
  rent: { base: 50, house1: 100, house2: 650, house3: 750, hotel: 750 },
  buildCost: { house: 150, hotel: 250 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Yellow Property ---
const ephraimHilltops = {
  type: "property",
  name: "Ephraim Hilltops",
  colorGroup: "yellow",
  price: 300,
  rent: { base: 50, house1: 300, house2: 400, house3: 500, hotel: 800 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Green Properties ---
const gushKatif = {
  type: "property",
  name: "Gush Katif",
  colorGroup: "green",
  price: 350,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 1000 },
  buildCost: { house: 150, hotel: 250 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const neveDekalim = {
  type: "property",
  name: "Neve Dekalim",
  colorGroup: "green",
  price: 350,
  rent: { base: 50, house1: 200, house2: 300, house3: 650, hotel: 800 },
  buildCost: { house: 150, hotel: 200 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const ganOr = {
  type: "property",
  name: "Gan Or",
  colorGroup: "green",
  price: 350,
  rent: { base: 50, house1: 100, house2: 300, house3: 650, hotel: 800 },
  buildCost: { house: 150, hotel: 200 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Purple Properties ---
const jerusalemHills = {
  type: "property",
  name: "Jerusalem Hills",
  colorGroup: "purple",
  price: 150,
  rent: { base: 10, house1: 200, house2: 250, house3: 300, hotel: 400 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const jerusalemHillsOrchard = {
  type: "property",
  name: "Jerusalem Hills Orchard",
  colorGroup: "purple",
  price: 150,
  rent: { base: 10, house1: 200, house2: 250, house3: 300, hotel: 400 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Gold Properties ---
const hevronElonMamrei = {
  type: "property",
  name: "Hevron Elon Mamrei",
  colorGroup: "gold",
  price: 240,
  rent: { base: 30, house1: 70, house2: 200, house3: 550, hotel: 650 },
  buildCost: { house: 80, hotel: 150 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const hevronLuxuryCondos = {
  type: "property",
  name: "Hevron Luxury Condos",
  colorGroup: "gold",
  price: 180,
  rent: { base: 25, house1: 60, house2: 175, house3: 500, hotel: 600 },
  buildCost: { house: 60, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const hevronHiTech = {
  type: "property",
  name: "Hevron Hi Tech",
  colorGroup: "gold",
  price: 180,
  rent: { base: 25, house1: 60, house2: 175, house3: 500, hotel: 600 },
  buildCost: { house: 60, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Board events map ---
const boardEvents = {
  3: { type: "property", card: schemRoyalEstates },
  1: { type: "property", card: schemYosephGardens },
  4: { type: "property", card: schemDreamResorts },
  7: { type: "property", card: ephraimHilltops },
  11: { type: "property", card: gushKatif },
  12: { type: "property", card: neveDekalim },
  14: { type: "property", card: ganOr },
  29: { type: "property", card: jerusalemHills },
  28: { type: "property", card: jerusalemHillsOrchard },
  35: { type: "property", card: hevronElonMamrei },
  37: { type: "property", card: hevronLuxuryCondos },
  38: { type: "property", card: hevronHiTech },
};

// --- Build 44 board positions ---
function buildBoardPositions(refSize = 1200, margin = 100, spacesPerSide = 11) {
  const positions = [];
  const step = (refSize - 2 * margin) / (spacesPerSide - 1);

  const topY = margin;
  for (let i = 0; i < spacesPerSide; i++) positions.push({ x: Math.round(margin + i * step), y: topY });
  const rightX = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: rightX, y: Math.round(topY + i * step) });
  const bottomY = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: Math.round(rightX - i * step), y: bottomY });
  const leftX = margin;
  for (let i = 1; i < spacesPerSide - 1; i++) positions.push({ x: leftX, y: Math.round(bottomY - i * step) });

  return positions.slice(0, 44);
}

const referenceSize = 1200;
const defaultBoardPositions = buildBoardPositions(referenceSize, 100, 11);


// --- React App Component ---
function App() {
  const [players, setPlayers] = useState([]);
  const [playerNames, setPlayerNames] = useState(["", ""]);
  const [currentPlayer, setCurrentPlayer] = useState(0);
  const [playerPositions, setPlayerPositions] = useState([]);
  const [playerBalances, setPlayerBalances] = useState([]);
  const [diceValue, setDiceValue] = useState(1);
  const [showPropertyModal, setShowPropertyModal] = useState(false);
  const [currentProperty, setCurrentProperty] = useState(null);
  const [showAssets, setShowAssets] = useState(null);

  // --- Start Game ---
  const startGame = () => {
    const filteredNames = playerNames.filter(name => name.trim() !== "");
    setPlayers(filteredNames);
    setPlayerPositions(new Array(filteredNames.length).fill(0));
    setPlayerBalances(new Array(filteredNames.length).fill(1500));
  };

  // --- Roll Dice ---
  const handleRoll = () => {
    const roll = Math.floor(Math.random() * 6) + 1;
    setDiceValue(roll);

    const newPositions = [...playerPositions];
    newPositions[currentPlayer] = (newPositions[currentPlayer] + roll) % 44;
    setPlayerPositions(newPositions);

    const landed = boardEvents[newPositions[currentPlayer]];
    if (landed && landed.type === "property") {
      setCurrentProperty(landed.card);
      setShowPropertyModal(true);
    }

    setCurrentPlayer((currentPlayer + 1) % players.length);
  };

  // --- Buy Property ---
  const buyProperty = () => {
    const updatedBalances = [...playerBalances];
    updatedBalances[currentPlayer] -= currentProperty.price;
    setPlayerBalances(updatedBalances);

    currentProperty.ownerIndex = currentPlayer;
    setShowPropertyModal(false);
  };

  // --- Pay Rent ---
  const payRent = (payerIndex, ownerIndex, amount) => {
    const updatedBalances = [...playerBalances];
    updatedBalances[payerIndex] -= amount;
    updatedBalances[ownerIndex] += amount;
    setPlayerBalances(updatedBalances);
  };

  // --- Show Player Assets ---
  const toggleAssets = (index) => {
    if (showAssets === index) {
      setShowAssets(null);
    } else {
      setShowAssets(index);
    }
  };

  // --- Render ---
  if (players.length === 0) {
    return (
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", height: "100vh" }}>
        <h2>Enter Player Names:</h2>
        {playerNames.map((name, idx) => (
          <input key={idx} type="text" value={playerNames[idx]} onChange={e => {
            const newNames = [...playerNames];
            newNames[idx] = e.target.value;
            setPlayerNames(newNames);
          }} style={{ margin: "5px" }} />
        ))}
        <button onClick={startGame} style={{ marginTop: "10px" }}>Start Game</button>
      </div>
    );
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center" }}>
      <h2>Current Player: {players[currentPlayer]}</h2>
      <Dice
        onRoll={handleRoll}
        disabled={players.length === 0}
      />
      <div style={{ position: "relative", marginTop: "20px" }}>
        <img src={boardImage} alt="Board" width={referenceSize} height={referenceSize} />
        {players.map((p, idx) => {
          const pos = defaultBoardPositions[playerPositions[idx]];
          return (
            <div key={idx} style={{
              position: "absolute",
              left: pos.x,
              top: pos.y,
              width: "20px",
              height: "20px",
              borderRadius: "50%",
              backgroundColor: idx === 0 ? "red" : "blue",
            }} />
          );
        })}
      </div>

      {/* Player Asset Buttons */}
      <div style={{ display: "flex", gap: "10px", marginTop: "20px" }}>
        {players.map((p, idx) => (
          <button key={idx} onClick={() => toggleAssets(idx)}>
            {p}'s Assets
          </button>
        ))}
      </div>

      {/* Assets Panel */}
      {showAssets !== null && (
        <div style={{ border: "1px solid black", padding: "10px", marginTop: "10px" }}>
          <h3>{players[showAssets]}'s Properties:</h3>
          <ul>
            {Object.values(boardEvents).filter(e => e.card.ownerIndex === showAssets).map(e => (
              <li key={e.card.name}>{e.card.name}</li>
            ))}
          </ul>
          <p>Balance: ${playerBalances[showAssets]}</p>
          <button onClick={() => setShowAssets(null)}>Close</button>
        </div>
      )}

      {/* Property Modal */}
      {showPropertyModal && currentProperty && (
        <div style={{
          position: "fixed", top: "30%", left: "30%", backgroundColor: "white",
          border: "1px solid black", padding: "20px", zIndex: 1000
        }}>
          <h3>{currentProperty.name}</h3>
          <p>Price: ${currentProperty.price}</p>
          {currentProperty.ownerIndex !== null
            ? <p>Owned by {players[currentProperty.ownerIndex]}</p>
            : <button onClick={buyProperty}>Buy</button>
          }
          <button onClick={() => setShowPropertyModal(false)} style={{ marginTop: "10px" }}>Close</button>
        </div>
      )}
    </div>
  );
}

export default App;
